    const handleLogin = (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        const { user, error } = authenticateUser(email, password);
        if (user) {
            onLoginSuccess(user);
        } else {
            if (error === 'pending_verification_agent' || error === 'pending_verification_investor') {
